const first = $input.first();
const body = first.json.body || first.json || {};
const binary = first.binary || {};
const now = new Date().toISOString();
const jobId = `ft_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

function findPhotoField(n) {
  const exact = `hero${n}_photo`;
  if (binary[exact]) return exact;
  return Object.keys(binary).find((key) => key === exact || key.startsWith(`${exact}_`) || key.includes(exact)) || null;
}

const heroes = [1, 2, 3, 4].map((n) => {
  const photoField = findPhotoField(n);
  const photo = photoField ? binary[photoField] : null;
  return {
    n,
    name: body[`hero${n}_name`] || '',
    description: body[`hero${n}_desc`] || '',
    relation: body[`hero${n}_rel`] || '',
    photoField,
    photoMime: photo?.mimeType || body[`hero${n}_photo_mime`] || null,
    photoFileName: photo?.fileName || body[`hero${n}_photo_name`] || null,
    hasPhoto: Boolean(photoField),
  };
}).filter((hero) => hero.name || hero.description || hero.photoField);

return [{
  json: {
    jobId,
    status: 'received',
    createdAt: now,
    source: 'fairyteller_create',
    order: {
      world: body.world || 'disney_light',
      location: body.location || '',
      artifact: body.artifact || '',
      email: String(body.email || '').toLowerCase(),
      illustrationStyle: body.illustration_style || 'disney',
      illustrationStylePrompt: body.illustration_style_prompt || '',
      lengthTarget: Number(body.length_target || 15000),
      chapters: Number(body.chapters || 5),
      language: body.language || 'ru',
      heroes,
    },
    pipeline: { next: 'fairyteller_text', previewEnabled: true, portraitizerEnabled: true },
  },
  binary: first.binary,
}];

const normalized = $('Normalize Order and Create Job').first().json;
const apiJob = $input.first().json;
return [{
  json: {
    ...normalized,
    jobId: apiJob.jobId || normalized.jobId,
    jobApi: apiJob,
  },
  binary: $('Normalize Order and Create Job').first().binary,
}];
